function isEmpty(source) {
    // Checks for null, undefined, not an array, or empty array
    return !Array.isArray(source) || source.length === 0;
}

logger.error("Source widgets: " + JSON.stringify(source));
var resultArray = [];
if(!isEmpty(source)){
logger.error("widgetarray length : "+source.length);
for(var i = 0; i < source.length; i++){
	var sourceWidgetId = source[i]._refResourceId;
	logger.error("sourceWidgetId ref: "+sourceWidgetId);

	try {

		var widgetResponse = openidm.query(
			"managed/alpha_kyid_tag",{
				 "_queryFilter": '_id eq "' + sourceWidgetId + '"'
			},
			["name"]
		);
		logger.error("Widget Response: " + JSON.stringify(widgetResponse));

		if (widgetResponse.result && widgetResponse.result.length == 1) {

			var widgetId = widgetResponse.result[0].name;
			logger.error("widgetId in response : "+widgetId);
			resultArray.push(widgetId);

		} else {
			logger.error("Exception occurred during widget to tag link " );
		}
	} catch (e) {
		logger.error("Exception occurred: " + e);  
	}

}
var resultString = resultArray.join(',');
logger.error("Result Array : " + resultString);
resultString;
}else{
	null;
}
